const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

(async () => {
  const browser = await puppeteer.launch({
    headless: 'new',
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();
  await page.goto('https://news.ycombinator.com', { waitUntil: 'networkidle2' });

  // Extract the top 5 story titles
  const titles = await page.evaluate(() => {
    const titleElements = document.querySelectorAll('.titleline > a');
    const topTitles = [];
    for (let i = 0; i < 5 && i < titleElements.length; i++) {
      topTitles.push(titleElements[i].textContent.trim());
    }
    return topTitles;
  });

  await browser.close();

  // Format and save titles
  const formattedTitles = titles.map((title, index) => `${index + 1}. ${title}`).join('\n');
  const titlesPath = path.join(__dirname, 'scraped_data', 'hn_titles.txt');
  fs.writeFileSync(titlesPath, formattedTitles);

  // Create log file
  const logContent = `STATUS: SUCCESS\nITEMS_SCRAPED: 5\nSOURCE: https://news.ycombinator.com`;
  const logPath = path.join(__dirname, 'scraped_data', 'scrape_log.txt');
  fs.writeFileSync(logPath, logContent);

  console.log('Scraping completed successfully!');
  console.log('Titles saved to:', titlesPath);
  console.log('Log saved to:', logPath);
})();
EOF

